USE aichat;

INSERT INTO `article` (`title`, `summary`, `content`, `cover_emoji`, `category`, `tags`, `view_count`) VALUES
('减脂期如何科学控制热量缺口', '了解热量缺口的原理，掌握每日500千卡黄金缺口的计算方法，避免过度节食带来的代谢损伤。', '## 什么是热量缺口？\n\n热量缺口 = 每日总消耗(TDEE) - 每日摄入热量\n\n当你的摄入低于消耗时，身体会动用储存的脂肪来供能，这就是减脂的基本原理。\n\n## 黄金法则：每日500千卡缺口\n\n研究表明，每日维持 **300-500千卡** 的热量缺口是最健康、最可持续的减脂方式：\n\n| 缺口大小 | 每周减重 | 可持续性 | 风险 |\n|---------|---------|---------|------|\n| 300kcal | 0.3kg | ⭐⭐⭐⭐⭐ | 极低 |\n| 500kcal | 0.5kg | ⭐⭐⭐⭐ | 低 |\n| 700kcal | 0.7kg | ⭐⭐ | 中等 |\n| 1000kcal+ | 1kg+ | ⭐ | 高 |\n\n## 如何计算你的TDEE？\n\n使用 Mifflin-St Jeor 公式：\n\n- **男性**：BMR = 10 × 体重(kg) + 6.25 × 身高(cm) - 5 × 年龄 - 161 + 5\n- **女性**：BMR = 10 × 体重(kg) + 6.25 × 身高(cm) - 5 × 年龄 - 161\n\n然后乘以活动系数：\n- 久坐不动：× 1.2\n- 轻度活动：× 1.375\n- 中度活动：× 1.55\n- 高度活动：× 1.725\n\n## ⚠️ 过度节食的危害\n\n当热量缺口超过 1000千卡/天时：\n1. **基础代谢下降**：身体进入节能模式\n2. **肌肉流失**：不仅减脂肪，还会减肌肉\n3. **情绪波动**：容易暴躁、焦虑\n4. **反弹风险**：恢复饮食后体重快速回升', '🔥', 'nutrition', '热量缺口,减脂原理,TDEE', 256),

('蛋白质摄入指南：减脂期的肌肉守护', '减脂期每天需要多少蛋白质？什么时候吃？本文详解蛋白质摄入的最佳策略。', '## 为什么减脂期要多吃蛋白质？\n\n蛋白质是减脂期最重要的营养素：\n\n1. **保护肌肉**：热量不足时，身体会分解肌肉供能\n2. **增加饱腹感**：蛋白质的饱腹感最强\n3. **食物热效应高**：消化蛋白质消耗其热量的 20-30%\n\n## 每天吃多少蛋白质？\n\n| 人群 | 推荐摄入量(g/kg体重) |\n|------|--------------------|\n| 普通成人 | 0.8-1.0 |\n| 减脂期 | 1.6-2.2 |\n| 增肌期 | 1.6-2.0 |\n\n## 高蛋白食物排行\n\n| 食物 | 每100g蛋白质 | 热量 |\n|------|------------|------|\n| 鸡胸肉 | 31g | 165kcal |\n| 虾仁 | 24g | 99kcal |\n| 希腊酸奶 | 10g | 59kcal |\n| 豆腐 | 8g | 76kcal |\n\n## 蛋白质摄入时机\n\n- **早餐**：至少 20-30g\n- **训练后30分钟内**：20-40g\n- **每餐均匀分配**：每餐 25-40g', '🥩', 'nutrition', '蛋白质,肌肉保护,减脂饮食', 189),

('5个最常见的减脂误区', '不吃碳水就能瘦？只做有氧最有效？揭开这些流行说法背后的真相。', '## 误区一：不吃碳水就能瘦\n\n低碳饮食初期体重快速下降，减的主要是水分和糖原，不是脂肪。\n\n✅ **正确做法**：选择复合碳水，控制总量而非完全不吃。\n\n## 误区二：只做有氧，不做力量\n\n纯有氧减脂效率不如"有氧+力量"组合。\n- 力量训练增加肌肉量 → 提高基础代谢\n- 纯有氧可能导致肌肉流失\n\n✅ **正确做法**：每周 3-4次力量训练 + 2-3次有氧\n\n## 误区三：运动后不能吃东西\n\n运动后是补充营养的最佳时机！\n\n✅ **正确做法**：运动后 30-60分钟内吃一餐\n\n## 误区四：局部减脂\n\n不可能只减某个部位的脂肪！\n\n✅ **正确做法**：全身减脂 + 针对部位力量训练塑形\n\n## 误区五：体重秤上的数字最重要\n\n更重要的是体脂率、围度和衣服松紧度。', '❌', 'myths', '减脂误区,碳水,有氧', 342),

('HIIT vs 有氧：哪种训练更减脂？', '高强度间歇训练和传统有氧运动，到底哪个减脂效果更好？', '## 什么是HIIT？\n\nHIIT = 高强度间歇训练，短时间高强度运动 + 短暂休息交替进行。\n\n## HIIT vs 稳态有氧对比\n\n| 对比项 | HIIT | 稳态有氧 |\n|--------|------|--------|\n| 时间效率 | ⭐⭐⭐⭐⭐ | ⭐⭐ |\n| 后燃效应 | ⭐⭐⭐⭐⭐ | ⭐ |\n| 入门难度 | 较高 | 低 |\n| 肌肉保护 | 较好 | 一般 |\n\n## 后燃效应(EPOC)\n\nHIIT训练结束后身体持续消耗热量长达 24-48小时。\n\n## 最佳策略：结合使用\n\n- 每周 2次 HIIT（20分钟）\n- 每周 2-3次稳态有氧（30-45分钟）\n- 每周 3-4次力量训练\n\n⚠️ 体重较大(BMI>28)的人群建议从低强度有氧开始。', '⚡', 'training', 'HIIT,有氧运动,减脂效率', 278),

('睡眠不足真的会发胖吗？', '研究表明睡眠不足7小时会增加肥胖风险41%。了解睡眠与减脂的科学关系。', '## 睡眠与体重的科学关系\n\n- 睡眠 < 6小时：肥胖风险增加 55%\n- 睡眠不足7小时：BMI平均增加 0.35\n\n## 为什么睡不够会胖？\n\n### 1. 激素失衡\n\n| 激素 | 睡眠充足 | 睡眠不足 |\n|------|---------|--------|\n| 瘦素 | 正常 | ↓ 下降18% |\n| 饥饿素 | 正常 | ↑ 上升28% |\n| 皮质醇 | 正常 | ↑ 持续偏高 |\n\n睡眠不足的人平均每天**多吃 385 千卡**！\n\n## 改善睡眠的 8 个技巧\n\n1. 固定作息时间\n2. 睡前1小时放下手机\n3. 保持卧室凉爽(18-20°C)\n4. 下午2点后不喝咖啡\n5. 睡前3小时不进食\n6. 避免睡前蓝光\n7. 睡前做5分钟深呼吸\n8. 只在床上睡觉\n\n**睡眠是免费的减脂补剂！**', '😴', 'mental', '睡眠,激素,肥胖', 198),

('减脂期的力量训练指南', '为什么减脂必须做力量训练？新手如何开始？本文给你一套完整的训练框架。', '## 力量训练为什么重要？\n\n1. **保持肌肉量**：减脂时身体倾向同时减肌肉\n2. **提高基础代谢**：每增加1kg肌肉，每天多消耗 50-70kcal\n3. **改善体态**：紧致有型比瘦而松好看\n4. **后燃效应**：训练后 24-72小时持续消耗额外热量\n\n## 推荐动作（复合动作为主）\n\n| 部位 | 推荐动作 | 组数×次数 |\n|------|---------|----------|\n| 腿/臀 | 深蹲、硬拉 | 4×8-12 |\n| 胸 | 俯卧撑、推胸 | 3×8-12 |\n| 背 | 引体向上、划船 | 3×8-12 |\n| 肩 | 推举、侧平举 | 3×10-15 |\n| 核心 | 平板支撑、卷腹 | 3×15-20 |\n\n## 渐进超负荷原则\n\n每周至少做到以下其中一项：\n- 增加重量（+2.5kg）\n- 增加次数（+1-2次）\n- 增加组数（+1组）\n\n✅ 记录每次训练的重量和次数，确保进步！', '🏋️', 'training', '力量训练,新手训练,肌肉', 312),

('情绪性进食：如何打破暴食循环', '压力大就想吃甜食？了解情绪性进食的心理学机制和应对策略。', '## 什么是情绪性进食？\n\n不是因为饿，而是因为情绪而吃东西。\n研究表明：**75%的过度进食是由情绪驱动的**\n\n## 情绪性饥饿 vs 真正饥饿\n\n| 特征 | 情绪性饥饿 | 真正饥饿 |\n|------|-----------|--------|\n| 发生速度 | 突然的 | 逐渐的 |\n| 特定渴望 | 只想吃某种食物 | 什么都想吃 |\n| 满足感 | 吃完还是想吃 | 吃饱就停 |\n| 罪恶感 | 吃完会后悔 | 不会 |\n\n## HALT 检查法\n\n想吃东西时先问自己：\n- **H**ungry？真的饿了吗？\n- **A**ngry？是在生气吗？\n- **L**onely？是感到孤独吗？\n- **T**ired？是累了？\n\n如果不是真的饿，用其他方式满足需求。\n\n记住：**偶尔的情绪性进食是正常的**，不要因为一次失败就放弃整个计划。', '🧠', 'mental', '情绪进食,暴食,心理学', 267),

('碳水循环法：高级减脂策略详解', '什么是碳水循环？如何通过调整每日碳水摄入来加速减脂？', '## 什么是碳水循环？\n\n根据训练强度调整每日碳水摄入量：\n- 高强度训练日 → 高碳水\n- 低强度/休息日 → 低碳水\n\n## 三天循环示例\n\n| 日 | 碳水 | 蛋白质 | 脂肪 | 训练 |\n|----|------|--------|------|------|\n| Day1 | 高(200-250g) | 中 | 低 | 腿部训练 |\n| Day2 | 低(50-80g) | 高 | 高 | 有氧/休息 |\n| Day3 | 中(120-150g) | 中 | 中 | 上肢训练 |\n\n## 适合人群\n\n✅ 有一定训练基础\n✅ 体脂率已较低想进一步减脂\n\n❌ 新手不建议\n❌ 饮食控制能力差的人', '🔄', 'nutrition', '碳水循环,高级策略,饮食计划', 145);

INSERT INTO `supplement` (`name`, `emoji`, `category`, `description`, `benefits`, `dosage`, `timing`, `side_effects`, `suitable_for`) VALUES
('乳清蛋白粉', '🥛', 'protein', '从牛奶中提取的快速吸收蛋白质，是健身人群最常用的蛋白质补充剂。含有完整的必需氨基酸，吸收速度快。', '促进肌肉修复和增长\n提高蛋白质摄入效率\n增加饱腹感\n方便快捷', '每日 20-40g（1-2勺）', '训练后 30 分钟内\n早餐时补充', '过量可能导致消化不良\n乳糖不耐受者选择分离乳清', '力量训练人群\n蛋白质摄入不足者\n减脂期需要高蛋白饮食者'),

('酪蛋白', '🧀', 'protein', '牛奶中的慢速消化蛋白质，消化时间长达6-8小时，能在较长时间内持续为身体提供氨基酸。', '缓慢释放氨基酸\n睡前服用可防止夜间肌肉分解\n饱腹感持久', '每日 20-40g\n睡前 30g 最佳', '睡前 30 分钟\n长时间不进食前', '消化较慢可能胀气\n乳糖不耐受者注意', '需要夜间保护肌肉者\n饮食不规律者'),

('肌酸一水合物', '⚡', 'creatine', '世界上研究最充分的运动补剂之一。能增加肌肉中的磷酸肌酸储备，提高ATP再生速度，提升爆发力和力量表现。', '提高力量和爆发力 5-15%\n增加肌肉体积\n改善高强度训练表现', '维持期：3-5g/天', '每天固定时间服用\n搭配碳水吸收更好', '初期体重增加1-2kg（水分）\n确保充足饮水', '力量训练者\n爆发力运动运动员'),

('支链氨基酸(BCAA)', '🔗', 'amino', '包含亮氨酸、异亮氨酸、缬氨酸三种必需氨基酸。可在训练中直接被肌肉利用供能。', '减少训练中肌肉分解\n促进肌肉蛋白质合成\n减轻训练后肌肉酸痛', '5-10g/次', '训练中少量多次饮用\n空腹训练前服用', '过量可能导致氨基酸失衡\n正常饮食者额外收益有限', '空腹训练者\n长时间训练(>90分钟)\n减脂期防止肌肉流失'),

('鱼油(Omega-3)', '🐟', 'vitamin', '富含EPA和DHA的必需脂肪酸补充剂。人体无法自行合成Omega-3，具有广泛的抗炎和健康益处。', '降低身体炎症反应\n改善心血管健康\n支持关节健康\n有助于脂肪代谢', '每日 1000-3000mg', '随餐服用\n早晚各一次', '高剂量可能有鱼腥味\n选择分子蒸馏产品', '几乎所有人\n关节不适者\n训练后需要抗炎恢复者'),

('维生素D3', '☀️', 'vitamin', '被称为阳光维生素，现代人普遍缺乏。参与钙吸收、免疫功能、肌肉恢复等多个生理过程。', '促进钙质吸收\n增强免疫功能\n改善情绪\n支持肌肉功能', '每日 2000-4000 IU', '随含脂肪的餐食服用\n早餐后较好', '极少副作用\n超大剂量可能高钙血症', '室内工作者\n训练者\n北方地区居民'),

('左旋肉碱', '🔥', 'amino', '帮助脂肪酸运输到线粒体进行氧化的氨基酸衍生物。红肉中也含有丰富的左旋肉碱。', '促进脂肪酸氧化\n可能提高有氧运动表现\n加速训练后恢复', '每日 1000-3000mg', '训练前 30-60 分钟\n搭配碳水提高吸收率', '少数人可能恶心\n甲状腺功能异常者慎用', '有氧训练者\n素食者\n想要提高脂肪氧化率者'),

('镁补充剂', '💎', 'vitamin', '人体必需的矿物质，参与300+种酶反应。对运动恢复和睡眠质量有重要影响。', '改善睡眠质量\n缓解肌肉痉挛\n支持神经系统放松\n参与能量代谢', '每日 200-400mg\n推荐甘氨酸镁', '睡前 30-60 分钟', '柠檬酸镁可能有轻泻作用\n肾功能不全者慎用', '睡眠质量差者\n容易抽筋的运动者\n高强度训练者'),

('咖啡因', '☕', 'other', '全球使用最广泛的精神活性物质。作为运动补剂能显著提升运动表现、专注力和脂肪氧化率。', '提高运动表现 3-5%\n增加脂肪氧化率\n提高专注力\n降低主观疲劳感', '运动前：3-6mg/kg体重\n日常不超过 400mg/天', '训练前 30-60 分钟\n避免下午2点后摄入', '过量导致焦虑失眠\n产生耐受性需周期停用', '需要提高训练表现者\n早起训练需要提神者'),

('复合维生素', '💊', 'vitamin', '包含多种维生素和矿物质的综合补充剂，用于填补日常饮食中可能存在的微量营养素缺口。', '填补饮食中的营养缺口\n支持免疫系统功能\n改善能量水平\n运动者需求更高', '每日 1 粒', '随早餐服用', '正常剂量几乎无副作用\n尿液变黄是正常的', '饮食不均衡者\n严格控制热量的减脂者\n高强度训练者');
